parameters.jsCode:
const dbData = $input.first().json;
const params = $('🔍 Валидация входа').first().json;

return [{ json: {
  ...params,
  script_text: dbData.script_text || '',
  timing_marks: dbData.timing_marks || [],
  prompt_text: dbData.prompt_text || '',
  scene_descriptions: dbData.scene_descriptions || [],
  style_reference: dbData.style_reference || '',
  title: dbData.title || '',
  concept: dbData.concept || '',
  visual_description: dbData.visual_description || ''
}}];

const sessionId = $('🔗 Объединение данных').first().json.session_id;
const binaryData = $input.first().binary;

if (!binaryData || !binaryData.data) {
  throw new Error('TTS не вернул аудиофайл');
}

return [{
  json: {
    session_id: sessionId,
    voice_file_name: `voice_${sessionId}.mp3`,
    ...$('🔗 Объединение данных').first().json
  },
  binary: binaryData
}];

const input = $input.first().json;
const taskId = input.id || input.task_id;
if (!taskId) throw new Error('Нет task_id в ответе GPTunnel');
return [{ json: {
  task_id: taskId,
  session_id: $('🔗 Объединение данных').first().json.session_id,
  poll_count: 0
}}];

const prev = $input.first().json;
const pollCount = (prev.poll_count || 0) + 1;

if (pollCount > 40) {
  throw new Error('Таймаут генерации видео: 40 попыток (10 мин)');
}

return [{ json: {
  task_id: prev.task_id || $('🔑 Извлечь task_id').first().json.task_id,
  session_id: prev.session_id || $('🔑 Извлечь task_id').first().json.session_id,
  poll_count: pollCount
}}];

const response = $json.body || $json;
const videoUrl = response.data?.[0]?.url || response.video_url || response.output || '';

if (!videoUrl) {
  throw new Error('GPTunnel не вернул URL видео: ' + JSON.stringify(response).substring(0, 300));
}

const sessionId = $('🔑 Извлечь task_id').first().json.session_id;

return [{ json: {
  session_id: sessionId,
  raw_video_url: videoUrl,
  ...$('🔗 Объединение данных').first().json
}}];

// Генерация SRT субтитров из timing_marks
const data = $('🔗 Объединение данных').first().json;
const sessionId = data.session_id;
const timingMarks = data.timing_marks || [];

if (timingMarks.length === 0) {
  const words = (data.script_text || '').split(/\s+/);
  const chunkSize = 6;
  let srt = '';
  let idx = 1;
  for (let i = 0; i < words.length; i += chunkSize) {
    const chunk = words.slice(i, i + chunkSize).join(' ');
    const startSec = Math.floor(i / chunkSize) * 3;
    const endSec = startSec + 3;
    srt += `${idx}\n${fmtSRT(startSec)} --> ${fmtSRT(endSec)}\n${chunk}\n\n`;
    idx++;
  }
  return [{ json: { session_id: sessionId, srt_content: srt } }];
}

let srt = '';
for (let i = 0; i < timingMarks.length; i++) {
  const mark = timingMarks[i];
  const nextMark = timingMarks[i + 1];
  srt += `${i + 1}\n${fmtSRT(mark.time)} --> ${fmtSRT(nextMark ? nextMark.time : mark.time + 3)}\n${mark.text}\n\n`;
}

return [{ json: { session_id: sessionId, srt_content: srt } }];

function fmtSRT(sec) {
  const h = String(Math.floor(sec / 3600)).padStart(2, '0');
  const m = String(Math.floor((sec % 3600) / 60)).padStart(2, '0');
  const s = String(Math.floor(sec % 60)).padStart(2, '0');
  return `${h}:${m}:${s},000`;
}

const data = $('🎬 URL видео').first().json;
const sessionId = data.session_id;

let cmd = 'ffmpeg -y';
cmd += ` -i /home/node/output/raw_${sessionId}.mp4`;
cmd += ` -i /home/node/output/voice_${sessionId}.mp3`;

let filters = [];
filters.push('[0:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2[base]');

const sf = data.subtitle_font || 'Arial';
const ss = data.subtitle_size || 42;
const so = data.subtitle_outline || 2;
filters.push(`[base]subtitles=/home/node/output/subs_${sessionId}.srt:force_style='FontName=${sf},FontSize=${ss},PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,Outline=${so},Alignment=2'[subbed]`);

let lastLabel = 'subbed';

if (data.watermark_url) {
  cmd += ` -i /home/node/output/watermark_${sessionId}.png`;
  const pos = data.watermark_position || 'top-right';
  let x = 'W-w-20', y = '20';
  if (pos === 'top-left') { x = '20'; y = '20'; }
  else if (pos === 'bottom-left') { x = '20'; y = 'H-h-20'; }
  else if (pos === 'bottom-right') { x = 'W-w-20'; y = 'H-h-20'; }
  const opacity = data.watermark_opacity || 0.7;
  filters.push(`[2:v]format=rgba,colorchannelmixer=aa=${opacity}[wm]`);
  filters.push(`[${lastLabel}][wm]overlay=${x}:${y}[watermarked]`);
  lastLabel = 'watermarked';
}

if (data.show_artikul && data.artikul) {
  filters.push(`[${lastLabel}]drawtext=text='${data.artikul}':fontsize=36:fontcolor=white:borderw=2:bordercolor=black:x=20:y=H-h-60[final]`);
  lastLabel = 'final';
}

cmd += ` -filter_complex "${filters.join(';')}" -map "[${lastLabel}]" -map 1:a`;
cmd += ' -c:v libx264 -preset fast -crf 23 -c:a aac -b:a 128k -shortest';
cmd += ` /home/node/output/final_${sessionId}.mp4`;

return [{ json: { session_id: sessionId, ffmpeg_cmd: cmd } }];

